prompts.prompt_zh:
{
  "type": "产品爆炸拆解图海报",
  "subject": "VR头戴设备",
  "style": "简洁高科技风格的3D渲染图，影棚布光(studio lighting)，发光装饰元素(glowing accents)",
  "background": "{argument name=\"background color\" default=\"柔和的紫蓝色渐变\"}",
  "header": {
    "logo": "∞ {argument name=\"product name\" default=\"Meta Quest 3\"}",
    "subtitle": "{argument name=\"main catchphrase\" default=\"从全然崭新的结构，开启全然崭新的现实。\"}"
  },
  "layout": {
    "centerpiece": "垂直堆叠式VR头戴设备爆炸拆解图，清晰展示9个独立的内部结构层：外壳(outer shell)、摄像头传感器(camera sensors)、搭载芯片的主板(motherboard with chip)、折叠式透镜(pancake lenses)、内部框架(internal frame)、电池组(battery packs)、侧边头带(side straps)、顶部头带(top strap)以及面部接触缓冲垫(facial interface cushion)。",
    "callout_labels": {
      "count": 8,
      "left_side": [
        "Snapdragon® XR2 Gen 2\n凭借压倒性的处理性能，实现真正的实时沉浸体验。",
        "可调节瞳距(IPD)机构\n适配更广泛的用户群体，提供舒适贴合的佩戴感。",
        "精密设计的头带系统\n融合人体工学(ergonomics)，兼顾舒适性与佩戴稳定性。"
      ],
      "right_side": [
        "面部面板(Faceplate)\n兼具精致外观设计与优化的重量分布。",
        "追踪摄像头(Tracking Camera)\n实现高精度位置追踪与环境感知能力。",
        "折叠式透镜(Pancake Lenses)\n超薄光学结构，提供宽广视场角(FOV)与高清成像效果。",
        "高性能电池(High-Performance Battery)\n经优化的电源管理系统，支撑长时间续航表现。",
        "柔软面部接口(Face Interface)\n即使长时间佩戴，亦能保持卓越舒适感。"
      ]
    },
    "footer": {
      "left_text_block": {
        "headline": "{argument name=\"bottom headline\" default=\"体验，始于结构的进化。\"}",
        "body": "每一个零部件，都凝聚着支撑沉浸式体验的前沿科技与精雕细琢的设计理念。Meta Quest 3，正从内部构造出发，孕育令人真切感知未来的全新体验。"
      },
      "right_logo": "∞ Meta"
    }
  }
}

